class Solution:
    def wordBreak(self, s, wordDict):
        words = set(wordDict)
        from functools import lru_cache
        n = len(s)
        import sys
        sys.setrecursionlimit(10000)
        @lru_cache(maxsize=None)
        def solve(i):
            if i == n:
                return True
            for j in range(i + 1, n + 1):
                if s[i:j] in words and solve(j):
                    return True
            return False
        return solve(0)

