var wordBreak = function(s, wordDict) {
    const words = new Set(wordDict);
    const n = s.length;
    const dp = new Array(n + 1).fill(false);
    dp[0] = true;
    for (let j = 1; j <= n; j++) {
        for (let i = 0; i < j; i++) {
            if (dp[i] && words.has(s.slice(i, j))) {
                dp[j] = true;
                break;
            }
        }
    }
    return dp[n];
};
